using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration -----------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Service setup -----------------------------------------------------------
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAIClientOptions
    {
        // Uses the default OpenAI endpoint; swap for Azure.AI.OpenAI if needed.
    }, apiKey));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

// --- Tools -------------------------------------------------------------------
var notebook = new ResearchNotebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            Console.WriteLine($"  🔍 Searching: \"{query}\"");
            return WebSearchTool.SearchAsync(query);
        },
        "web_search",
        "Searches the web for a query and returns a list of results with titles, URLs, and snippets."),

    AIFunctionFactory.Create(
        ([Description("A concise note capturing a key finding")] string note,
         [Description("The source URL for this finding")] string sourceUrl) =>
        {
            notebook.AddNote(note, sourceUrl);
            Console.WriteLine($"  📝 Noted: {note[..Math.Min(note.Length, 80)]}...");
            return "Note saved.";
        },
        "save_note",
        "Saves a research note with its source URL for later summarization."),

    AIFunctionFactory.Create(
        () =>
        {
            var notes = notebook.GetNotes();
            Console.WriteLine($"  📋 Reading {notes.Count} note(s)");
            return notes;
        },
        "read_notes",
        "Reads all previously saved research notes."),
};

// --- Agent -------------------------------------------------------------------
const string instructions = """
    You are a research assistant. When given a topic, you:
    1. Search the web for relevant, recent information using multiple queries.
    2. Save important findings as notes using save_note (always include the source URL).
    3. After gathering enough information (at least 3-5 searches), read your notes and
       produce a well-structured summary with source citations.
    Be thorough but concise. Vary your search queries to cover different angles.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings.",
    tools: tools,
    loggerFactory: loggerFactory);

// --- Run ---------------------------------------------------------------------
Console.WriteLine("╔════════════════════════════════════════╗");
Console.WriteLine("║       🔬 Research Agent                ║");
Console.WriteLine("╚════════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "latest advances in quantum computing";
}

Console.WriteLine();
Console.WriteLine($"Researching: \"{topic}\"");
Console.WriteLine(new string('─', 50));

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine();
Console.WriteLine(new string('═', 50));
Console.WriteLine("📄 RESEARCH SUMMARY");
Console.WriteLine(new string('═', 50));
Console.WriteLine(response.Text);
Console.WriteLine();
Console.WriteLine($"Notes collected: {notebook.GetNotes().Count}");

// =============================================================================
// Supporting types
// =============================================================================

/// <summary>Simulated web search tool that returns plausible results.</summary>
static class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    public static async Task<List<SearchResult>> SearchAsync(string query)
    {
        // In production, replace with a real search API (Bing Search, Google Custom Search, etc.)
        // This uses a deterministic simulation so the app compiles and runs without extra API keys.
        await Task.Delay(250); // simulate network latency

        var hash = Math.Abs(query.GetHashCode());
        var results = new List<SearchResult>();

        string[] domains = ["arxiv.org", "nature.com", "techcrunch.com", "bbc.com/news", "reuters.com",
                            "wikipedia.org", "scholar.google.com", "mit.edu", "stanford.edu"];
        string[] snippetPrefixes = [
            "Recent studies show that",
            "A 2025 report highlights",
            "According to researchers,",
            "New findings suggest that",
            "Industry experts note that",
        ];

        for (int i = 0; i < 4; i++)
        {
            var domain = domains[(hash + i) % domains.Length];
            var prefix = snippetPrefixes[(hash + i) % snippetPrefixes.Length];
            results.Add(new SearchResult(
                Title: $"{query} - {(i == 0 ? "Overview" : i == 1 ? "Analysis" : i == 2 ? "Research" : "Latest News")}",
                Url: $"https://{domain}/article/{hash + i}",
                Snippet: $"{prefix} {query.ToLowerInvariant()} is a rapidly evolving area with significant implications. " +
                         $"Key developments include improved methodologies and broader applications in various fields."));
        }

        return results;
    }
}

record SearchResult(string Title, string Url, string Snippet);

/// <summary>Thread-safe notebook for collecting research findings.</summary>
class ResearchNotebook
{
    private readonly List<NoteEntry> _notes = [];
    private readonly Lock _lock = new();

    public void AddNote(string note, string sourceUrl)
    {
        lock (_lock)
        {
            _notes.Add(new NoteEntry(note, sourceUrl, DateTime.UtcNow));
        }
    }

    public IReadOnlyList<NoteEntry> GetNotes()
    {
        lock (_lock)
        {
            return _notes.ToList().AsReadOnly();
        }
    }
}

record NoteEntry(string Note, string SourceUrl, DateTime Timestamp);

